import { Component } from '@angular/core';
import { MatCardModule } from '@angular/material/card';

@Component({
  selector: 'app-habitaciones',
  standalone: true,
  imports: [MatCardModule],
  template: `
    <mat-card>
      <mat-card-header>
        <mat-card-title>Gestión de habitaciones</mat-card-title>
        <mat-card-subtitle>Crear, editar, eliminar y listar habitaciones</mat-card-subtitle>
      </mat-card-header>
      <mat-card-content>
        <p>Lista de habitaciones y formulario (RoomManagementComponent / RoomFormComponent).</p>
      </mat-card-content>
    </mat-card>
  `,
  styles: [],
})
export class HabitacionesComponent {}
